setup.Calc.java:
public class Calc {
    public int add(int a, int b) {
        return a + b;
    }

    public int subtract(int a, int b) {
        return a - b;
    }
}

setup.Main.java:
public class Main {
    public static void main(String[] args) {
        Calc calc = new Calc();
        System.out.println(calc.add(2, 3));
        System.out.println(calc.subtract(5, 1));
    }
}
